import{c as a,Q as i,j as s,m as t}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Ideas","description":"","frontmatter":{},"headers":[],"relativePath":"ideas.md","filePath":"ideas.md","lastUpdated":1781973909000}'),r={name:"ideas.md"};function o(d,e,l,c,n,u){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="ideas" tabindex="-1">Ideas <a class="header-anchor" href="#ideas" aria-label="Permalink to &quot;Ideas&quot;">​</a></h1><p>This page captures larger workflow ideas and staged product notes. Some ideas may have a first implementation while later workflow extensions remain exploratory.</p><h2 id="smart-set-builder-from-seed-tracks" tabindex="-1">Smart Set Builder From Seed Tracks <a class="header-anchor" href="#smart-set-builder-from-seed-tracks" aria-label="Permalink to &quot;Smart Set Builder From Seed Tracks&quot;">​</a></h2><p>The first Smart Set Builder version adds a dedicated SET tab that generates an ordered DJ set preview from either <code>1-5</code> manual seed tracks or <code>3-5</code> auto anchors chosen by the backend. The goal is not just &quot;more similar tracks&quot;; it acts as a curator over existing analysis models and produces a sequence for listening, digging, or set preparation.</p><p>The first version works without training a new model:</p><ul><li>use MERT similarity for musical/audio closeness;</li><li>use MAEST embeddings, but not MAEST genre labels, for audio-model agreement;</li><li>use CLAP audio embeddings from stored analysis, without a text prompt;</li><li>use a broad SONARA feature block for rhythm, dynamics, perception, tonal texture, spectral/timbre values, and saved array summaries;</li><li>use promoted classifier scores such as <code>abstract_edge</code>, <code>break_energy</code>, or <code>voice_presence</code> as optional target, avoid, or mood-curve signals;</li><li>use file-tag BPM/key first, with SONARA fallback, as soft transition-ordering signals rather than core vibe ranking.</li></ul><p>Suggested modes:</p><ul><li><code>similar_crate</code>: stay close to the seed tracks and rank by strong agreement across MERT, MAEST, SONARA, and classifier scores.</li><li><code>weird_adjacent</code>: keep enough similarity to remain relevant, but prefer candidates with unusual classifier/model disagreement or more experimental texture.</li><li><code>balanced_set</code>: generate a DJ-oriented list with bridge tracks, BPM/energy compatibility, and reduced repetition between adjacent tracks.</li><li><code>discovery</code>: allow riskier candidates and reserve part of the list for low-confidence tracks that could reveal useful new classifier positives.</li></ul><p>Implemented controls:</p><ul><li>manual or auto seed source;</li><li>target length, defaulting to 24;</li><li>diversity amount;</li><li>energy curve such as warmup, balanced, peak, or wave;</li><li>classifier targets, avoid rules, and start/end classifier curves.</li></ul><p>The generated result explains why each track was selected, for example <code>seed_anchor</code>, <code>similar_to_seed</code>, <code>bridge</code>, <code>weird_adjacent</code>, <code>discovery</code>, <code>classifier_match</code>, or <code>mood_shift</code>, and exposes the underlying MERT, MAEST, CLAP, SONARA group, classifier, and transition scores for manual review.</p><p>Possible API shape:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/set-builder/generate</span></span></code></pre></div><p>Input fields:</p><ul><li><code>seed_mode</code></li><li><code>seed_track_ids</code></li><li><code>auto_seed_count</code></li><li><code>limit</code></li><li><code>mode</code></li><li><code>diversity</code></li><li><code>energy_curve</code></li><li><code>classifier_targets</code></li><li><code>classifier_avoid</code></li><li><code>classifier_curves</code></li></ul><p>Output fields:</p><ul><li>ordered track rows;</li><li>selection reason;</li><li>similarity, SONARA group, transition, classifier, and diversity scores;</li><li>relevant classifier scores;</li><li>set-order transition metadata.</li></ul><p>Later extensions could send selected tracks to Rhythm Lab, mark them as reviewed, export XLSX lists, exclude already reviewed/exported tracks, or save generated sessions for iterative active-learning loops.</p>',18)])])}const h=a(r,[["render",o]]);export{m as __pageData,h as default};
